import{_ as i,o as t,c as l,ag as r}from"./chunks/framework.DgcAjFZS.js";const u=JSON.parse('{"title":"推理优化工程师 — 工作全景图","description":"","frontmatter":{},"headers":[],"relativePath":"inference/engineer-overview.md","filePath":"inference/engineer-overview.md"}'),a={name:"inference/engineer-overview.md"};function n(o,e,s,d,h,c){return t(),l("div",null,[...e[0]||(e[0]=[r('<h1 id="推理优化工程师-—-工作全景图" tabindex="-1">推理优化工程师 — 工作全景图 <a class="header-anchor" href="#推理优化工程师-—-工作全景图" aria-label="Permalink to &quot;推理优化工程师 — 工作全景图&quot;">​</a></h1><blockquote><p>2026-03-02 | 基于行业实际岗位需求整理</p></blockquote><hr><h2 id="日常工作分类" tabindex="-1">日常工作分类 <a class="header-anchor" href="#日常工作分类" aria-label="Permalink to &quot;日常工作分类&quot;">​</a></h2><p>推理优化工程师的工作大致分为 5 个层次，从上到下越来越底层：</p><hr><h3 id="第1层-serving-系统工程-最常见" tabindex="-1">第1层：Serving 系统工程（最常见） <a class="header-anchor" href="#第1层-serving-系统工程-最常见" aria-label="Permalink to &quot;第1层：Serving 系统工程（最常见）&quot;">​</a></h3><p>这是大多数公司招推理优化工程师的核心需求。</p><p><strong>日常工作：</strong></p><ul><li>基于 vLLM / SGLang / TensorRT-LLM 搭建和维护推理服务</li><li>调优 serving 参数：batch size、max_num_seqs、chunked prefill size、GPU memory utilization</li><li>实现 PD 分离（Prefill-Decode Disaggregation）部署架构</li><li>多模型混合部署、多 LoRA 并发服务</li><li>构建负载均衡、自动扩缩容、故障恢复</li><li>监控和 profiling：TTFT、TPS、P99 latency、GPU 利用率</li></ul><p><strong>你需要补的：</strong></p><ul><li>大规模集群部署经验（多机多卡、跨节点通信）</li><li>PD 分离的实际部署和调优</li><li>生产环境的监控体系搭建</li></ul><hr><h3 id="第2层-量化与压缩-高频需求" tabindex="-1">第2层：量化与压缩（高频需求） <a class="header-anchor" href="#第2层-量化与压缩-高频需求" aria-label="Permalink to &quot;第2层：量化与压缩（高频需求）&quot;">​</a></h3><p>把模型变小变快，同时尽量不掉精度。</p><p><strong>日常工作：</strong></p><ul><li>选择量化方案：FP8 / INT8 / INT4 / AWQ / GPTQ，根据硬件和精度要求决策</li><li>跑量化 calibration，评估量化后的精度损失</li><li>Mixed-precision 策略：哪些层用高精度，哪些层可以激进量化</li><li>KV Cache 量化（FP8 KV cache）</li><li>模型剪枝（structured pruning）和知识蒸馏</li></ul><p><strong>你需要补的：</strong></p><ul><li>量化的数学原理（Hessian-based、activation-aware）</li><li>实际跑过 GPTQ/AWQ/FP8 量化流程</li><li>量化精度评估方法论</li></ul><hr><h3 id="第3层-kernel-开发-核心竞争力-高薪区" tabindex="-1">第3层：Kernel 开发（核心竞争力，高薪区） <a class="header-anchor" href="#第3层-kernel-开发-核心竞争力-高薪区" aria-label="Permalink to &quot;第3层：Kernel 开发（核心竞争力，高薪区）&quot;">​</a></h3><p>写 GPU kernel，这是推理优化最硬核的部分。</p><p><strong>日常工作：</strong></p><ul><li>用 CUDA / Triton 写自定义 attention kernel</li><li>优化 GEMM（矩阵乘法）：针对特定 shape 调优</li><li>实现新的 attention 变体（MLA、Sparse Attention、Linear Attention）</li><li>Fused kernel：把多个操作融合成一个 kernel 减少内存访问</li><li>针对新硬件（H100、B200、MI300X）适配和优化 kernel</li></ul><p><strong>你需要补的（这是最大的 gap）：</strong></p><ul><li>CUDA 编程：thread/block/grid、shared memory、warp-level primitives</li><li>Triton 编程：比 CUDA 更高层，但也需要理解 GPU 架构</li><li>GPU 内存层次：L1/L2 cache、shared memory、global memory 的访问模式</li><li>性能分析：nsight compute、roofline model</li></ul><p><strong>关键资源：</strong></p><ul><li><a href="https://docs.nvidia.com/cuda/cuda-c-programming-guide/" target="_blank" rel="noreferrer">CUDA C++ Programming Guide</a></li><li><a href="https://triton-lang.org/main/getting-started/tutorials/" target="_blank" rel="noreferrer">Triton Tutorials</a></li><li><a href="https://github.com/Dao-AILab/flash-attention" target="_blank" rel="noreferrer">FlashAttention 源码</a> — 学 kernel 优化的最佳教材</li><li><a href="https://github.com/NVIDIA/cutlass" target="_blank" rel="noreferrer">CUTLASS</a> — NVIDIA 的 GEMM 模板库</li></ul><hr><h3 id="第4层-模型架构优化-偏研究" tabindex="-1">第4层：模型架构优化（偏研究） <a class="header-anchor" href="#第4层-模型架构优化-偏研究" aria-label="Permalink to &quot;第4层：模型架构优化（偏研究）&quot;">​</a></h3><p>从模型结构层面提升推理效率。</p><p><strong>日常工作：</strong></p><ul><li>设计推理友好的 attention 机制（GQA → MQA → MLA 的演进）</li><li>Speculative decoding 方案设计和实现</li><li>Early exit / adaptive computation</li><li>MoE 路由优化和 expert 并行策略</li><li>长上下文优化：sparse attention pattern、sliding window、chunk-based</li></ul><p><strong>你需要补的：</strong></p><ul><li>各种 attention 变体的原理和 trade-off</li><li>Speculative decoding 的实现细节</li><li>MoE 架构的推理特性</li></ul><hr><h3 id="第5层-系统架构设计-偏-senior-architect" tabindex="-1">第5层：系统架构设计（偏 senior / architect） <a class="header-anchor" href="#第5层-系统架构设计-偏-senior-architect" aria-label="Permalink to &quot;第5层：系统架构设计（偏 senior / architect）&quot;">​</a></h3><p>设计整个推理系统的架构。</p><p><strong>日常工作：</strong></p><ul><li>PD 分离 vs 一体化部署的架构决策</li><li>多级缓存设计（GPU → CPU → SSD）</li><li>跨数据中心的推理路由</li><li>成本优化：在 latency/throughput/cost 三角中找最优解</li><li>硬件选型：H100 vs MI300X vs TPU，不同场景怎么选</li></ul><hr><h2 id="你的定位分析" tabindex="-1">你的定位分析 <a class="header-anchor" href="#你的定位分析" aria-label="Permalink to &quot;你的定位分析&quot;">​</a></h2><p>Pan老师，根据你的背景：</p><table tabindex="0"><thead><tr><th>层次</th><th>你的现状</th><th>优先级</th></tr></thead><tbody><tr><td>Serving 系统工程</td><td>后端出身 + 了解 vLLM/SGLang → 上手快</td><td>⭐⭐⭐ 先拿这个进门</td></tr><tr><td>量化与压缩</td><td>有后训练经验，但量化实操少</td><td>⭐⭐ 必须补</td></tr><tr><td>Kernel 开发</td><td>最大 gap，CUDA/Triton 经验可能不足</td><td>⭐⭐⭐ 长期核心竞争力</td></tr><tr><td>模型架构优化</td><td>Transformer 理解深入，有基础</td><td>⭐⭐ 结合 Agentic RL 方向</td></tr><tr><td>系统架构设计</td><td>后端架构经验可迁移</td><td>⭐ 工作中积累</td></tr></tbody></table><h2 id="建议的突破路径" tabindex="-1">建议的突破路径 <a class="header-anchor" href="#建议的突破路径" aria-label="Permalink to &quot;建议的突破路径&quot;">​</a></h2><h3 id="短期-1-2个月-拿-serving-工程进门" tabindex="-1">短期（1-2个月）：拿 Serving 工程进门 <a class="header-anchor" href="#短期-1-2个月-拿-serving-工程进门" aria-label="Permalink to &quot;短期（1-2个月）：拿 Serving 工程进门&quot;">​</a></h3><ul><li>在实际项目中部署 vLLM/SGLang，跑通完整的生产级 serving pipeline</li><li>做一次完整的量化实验（AWQ/GPTQ/FP8），写对比报告</li><li>能说清楚 PD 分离的原理和部署方案</li></ul><h3 id="中期-3-4个月-补-kernel-开发能力" tabindex="-1">中期（3-4个月）：补 Kernel 开发能力 <a class="header-anchor" href="#中期-3-4个月-补-kernel-开发能力" aria-label="Permalink to &quot;中期（3-4个月）：补 Kernel 开发能力&quot;">​</a></h3><ul><li>学 Triton（比 CUDA 门槛低，但足够实用）</li><li>从实现一个简单的 fused softmax kernel 开始</li><li>读 FlashAttention 的 Triton 实现，理解 tiling 和 memory coalescing</li><li>目标：能写出 production-quality 的 Triton kernel</li></ul><h3 id="长期-6个月-建立差异化" tabindex="-1">长期（6个月+）：建立差异化 <a class="header-anchor" href="#长期-6个月-建立差异化" aria-label="Permalink to &quot;长期（6个月+）：建立差异化&quot;">​</a></h3><ul><li>CUDA kernel 开发能力（这是天花板最高的方向）</li><li>结合你的 Agentic RL 背景 — &quot;RL + 推理优化&quot;的交叉点非常稀缺 <ul><li>比如：RL rollout 的推理优化、agent 场景的 speculative decoding</li><li>SGLang 已经在做 RL 集成，这是你两条线交汇的地方</li></ul></li></ul><hr><h2 id="面试常见考点" tabindex="-1">面试常见考点 <a class="header-anchor" href="#面试常见考点" aria-label="Permalink to &quot;面试常见考点&quot;">​</a></h2><ol><li><strong>Transformer 推理的计算瓶颈在哪？Prefill 和 Decode 分别是 compute-bound 还是 memory-bound？</strong></li><li><strong>PagedAttention 解决了什么问题？和传统的连续 KV cache 分配相比优势在哪？</strong></li><li><strong>解释 continuous batching 的工作原理，和 static batching 的区别</strong></li><li><strong>FP8 量化和 INT8 量化的区别？什么场景用哪个？</strong></li><li><strong>Speculative decoding 的原理？什么条件下加速效果好？</strong></li><li><strong>GQA/MQA/MLA 各自的 trade-off？</strong></li><li><strong>如何诊断推理服务的性能瓶颈？用什么工具？</strong></li><li><strong>PD 分离的动机和架构设计？</strong></li><li><strong>给你一个模型和硬件配置，怎么估算 throughput 和显存占用？</strong></li><li><strong>Roofline model 是什么？怎么用它分析 kernel 性能？</strong></li></ol><hr><blockquote><p>这份文档会随你的学习进展更新。 有具体问题随时问 🐼</p></blockquote>',56)])])}const p=i(a,[["render",n]]);export{u as __pageData,p as default};
